                    <h2 id="account-departments-POSTapi-v1-accounts-departments">Create Department</h2>

<p>
</p>

<p>Create a new department.</p>

<span id="example-requests-POSTapi-v1-accounts-departments">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost/api/v1/accounts/departments" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"department_name\": \"architecto\",
    \"department_head_id\": \"architecto\",
    \"active\": false
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/accounts/departments"
);

