                <h1 id="library-responsibility-centers">Library - Responsibility Centers</h1>

    <p>APIs for managing responsibility centers</p>

                                <h2 id="library-responsibility-centers-GETapi-v1-libraries-responsibility-centers">List Responsibility Centers</h2>

<p>
</p>



<span id="example-requests-GETapi-v1-libraries-responsibility-centers">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost/api/v1/libraries/responsibility-centers?search=architecto&amp;per_page=16&amp;show_all=&amp;show_inactive=&amp;column_sort=architecto&amp;sort_direction=architecto&amp;paginated=" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/libraries/responsibility-centers"
);

const params = {
    "search": "architecto",
    "per_page": "16",
    "show_all": "0",
    "show_inactive": "0",
    "column_sort": "architecto",
    "sort_direction": "architecto",
    "paginated": "0",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
