    --get "http://localhost/api/v1/logs?search=architecto&amp;per_page=16&amp;column_sort=architecto&amp;sort_direction=architecto&amp;log_id=architecto" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


