                                <h2 id="request-quotations-GETapi-v1-request-quotations">List Purchase Requests with RFQs</h2>

<p>
</p>

<p>Retrieve a paginated list of purchase requests that have RFQs.</p>

<span id="example-requests-GETapi-v1-request-quotations">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost/api/v1/request-quotations?search=architecto&amp;per_page=16&amp;show_all=&amp;column_sort=architecto&amp;sort_direction=architecto&amp;paginated=" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/request-quotations"
);

const params = {
    "search": "architecto",
    "per_page": "16",
    "show_all": "0",
    "column_sort": "architecto",
    "sort_direction": "architecto",
    "paginated": "0",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>

