                    <h2 id="users-POSTapi-v1-accounts-users">Create User</h2>

<p>
</p>

<p>Create a new user.</p>

<span id="example-requests-POSTapi-v1-accounts-users">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost/api/v1/accounts/users" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"employee_id\": \"architecto\",
    \"firstname\": \"architecto\",
    \"middlename\": \"architecto\",
    \"lastname\": \"architecto\",
    \"sex\": \"architecto\",
    \"department_id\": \"architecto\",
    \"section_id\": \"architecto\",
    \"position\": \"architecto\",
    \"designation\": \"architecto\",
    \"username\": \"architecto\",
    \"email\": \"gbailey@example.net\",
    \"phone\": \"architecto\",
    \"password\": \"|]|{+-\",
    \"restricted\": false,
    \"roles\": [
        \"architecto\"
    ]
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost/api/v1/accounts/users"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "employee_id": "architecto",
    "firstname": "architecto",
    "middlename": "architecto",
    "lastname": "architecto",
    "sex": "architecto",
    "department_id": "architecto",
    "section_id": "architecto",
    "position": "architecto",
    "designation": "architecto",
    "username": "architecto",
    "email": "gbailey@example.net",
    "phone": "architecto",
    "password": "|]|{+-",
    "restricted": false,
    "roles": [
        "architecto"
    ]
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

</span>

<span id="example-responses-POSTapi-v1-accounts-users">
            <blockquote>
            <p>Example response (201):</p>
        </blockquote>
                <pre>

<code class="language-json" style="max-height: 300px;">{
